SELECT upload_type, COUNT(*) AS number_of_uploads
FROM uploads
GROUP BY upload_type;

SELECT mod_id, download_count, last_download_date
FROM mod_downloads
WHERE download_count > 50;

SELECT COUNT(*) AS incompatible_mod_count
FROM game_mods
WHERE compatibility_status = 'incompatible';

SELECT COUNT(*) 
FROM mod_comments 
WHERE comment_date >= '2023-01-01';

SELECT download_count AS total_downloads
FROM mod_downloads
WHERE mod_id = 0;

SELECT mod_id, download_count, last_download_date
FROM mod_downloads
WHERE mod_id = 1;

SELECT download_count, last_download_date
FROM mod_downloads
WHERE download_count = (SELECT MAX(download_count) FROM mod_downloads);

SELECT game_id, COUNT(mod_id) AS mod_count
FROM game_mods
GROUP BY game_id;
